renderHeadings = function(){
 const map=[
  ['routesEyebrow', N('itinerarios')],['routesTitle','Itinerarios académicos oficiales'],['routesDescription','Panel de acceso a fuentes oficiales sobre vías tras ESO, Bachillerato, FP y otras enseñanzas.'],
  ['bachEyebrow', N('bach')],['bachTitle','Bachillerato, materias y decisiones'],['bachDescription','Modalidades, materias estratégicas y enlaces oficiales para decidir con criterio.'],
  ['pondEyebrow', N('ponderaciones')],['pondTitle','Ponderaciones, notas y acceso universitario'],['pondDescription','Consulta orientativa con acceso directo a CIUG. El valor exacto cambia por curso y grado.'],['ruleCardTitle','Cómo leer las ponderaciones'],['ruleCardP1','Una materia puede ser muy útil si pondera 0,2 y además el alumno puede obtener una buena nota realista.'],['ruleCardP2','No siempre conviene escoger la materia que pondera más si la calificación esperable será muy baja. Hay que simular escenarios.'],['pondSourceTitle','Fuentes clave'],['pondSourceDescription','Admisión SUG, notas de corte y documento oficial de ponderaciones.'],['areaPanelTitle','Buscar por familia o área'],['areaPanelDescription','Selecciona una familia para ver estudios y rutas relacionadas.'],
  ['fpEyebrow', N('fp')],['fpTitle','Formación Profesional'],['fpDescription','Ciclos, familias, oferta por centros, admisión y continuidad académica con fuentes oficiales.'],
  ['uniEyebrow', N('universidad')],['uniTitle','Universidad: grados, créditos, acceso y títulos oficiales'],['uniDescription','Información organizada sobre RUCT, QEDU, CIUG, créditos ECTS, títulos oficiales, másteres habilitantes y salidas reguladas.'],['mastersTitle','Másteres habilitantes, ECTS y profesiones reguladas'],['mastersDescription','Un grado, un máster oficial y un máster habilitante no son lo mismo. Comprueba siempre RUCT y normativa.']
 ];
 map.forEach(([id,val])=>{const el=document.getElementById(id);if(el)el.textContent=val});
}

const UNI_V09=[
 {title:'QEDU: qué estudiar y dónde',body:'Punto de partida para localizar grados y universidades. Úsalo para explorar oferta, después verifica oficialidad en RUCT.',sources:['qedu','ruct']},
 {title:'RUCT: oficialidad del título',body:'Sirve para comprobar universidades, centros y títulos oficiales. Es imprescindible si hay duda entre título oficial y título propio.',sources:['ruct','ruct-faq']},
 {title:'Créditos ECTS',body:'Los créditos ECTS expresan la carga de trabajo del estudiante. Muchos grados se organizan en 240 ECTS, pero debe verificarse en el plan oficial de cada título.',sources:['rd-822-2021','ruct']},
 {title:'Acceso y admisión en Galicia',body:'La CIUG centraliza admisión al SUG, notas de corte, matrícula, ponderaciones y procedimientos. Las notas de corte son referencias, no garantías.',sources:['ciug-admision','ciug-notas-corte','ciug-ponderaciones-2026']},
 {title:'Títulos oficiales, propios y másteres',body:'Un título propio puede tener valor formativo, pero no sustituye a un título oficial cuando este es requisito académico o profesional.',sources:['ruct','rd-822-2021']},
 {title:'Profesiones reguladas',body:'Arquitectura, abogacía/procura, Psicología General Sanitaria, profesorado de Secundaria y algunas ingenierías pueden requerir formación habilitante posterior.',sources:['ruct-faq','rd-822-2021']}
];

renderStaticSections = function(){
  document.getElementById('routeCards').innerHTML=contentCards(ROUTES);
  document.getElementById('bachCards').innerHTML=contentCards(BACH);
  document.getElementById('bachWarning').innerHTML='<strong>'+T('important')+':</strong> '+T('officialNote');
  document.getElementById('fpCards').innerHTML=contentCards(FP);
  document.getElementById('universityCards').innerHTML=contentCards(UNI_V09);
  document.getElementById('masterCards').innerHTML=state.data.studies.filter(p=>p.regulated?.toLowerCase().includes('máster')||p.level?.toLowerCase().includes('máster')).slice(0,6).map(p=>programCard(p)).join('');
  document.getElementById('ponderationLinks').innerHTML=sourceLinks(['ciug-admision','ciug-notas-corte','ciug-ponderaciones-2026']);
  document.getElementById('areaButtons').innerHTML=[...new Set(state.data.studies.map(p=>p.family))].map(f=>`<button type="button" data-family="${escapeHTML(f)}">${escapeHTML(f)}</button>`).join('');
  document.querySelectorAll('#areaButtons button').forEach(b=>b.onclick=()=>document.getElementById('areaOutput').innerHTML=programs('', 'all', b.dataset.family).map(p=>programCard(p)).join(''));
  document.getElementById('scholarshipCards').innerHTML=state.data.scholarships.map(s=>`<article class="scholarship-card"><h2>${escapeHTML(s.title)}</h2><p>${escapeHTML(s.summary)}</p><p><strong>Prazo/estado:</strong> ${escapeHTML(s.period)}</p>${sourceLinks(s.sources)}</article>`).join('');
  document.getElementById('reservedCards').innerHTML=state.data.reservations.map(s=>`<article class="scholarship-card"><h2>${escapeHTML(s.title)}</h2><p>${escapeHTML(s.summary)}</p>${sourceLinks(s.sources)}</article>`).join('');
  renderSources(); renderFAQ();
}

renderQuestionChips = function(){
  const qs=[
    'Quiero Psicología pero no se me dan bien las matemáticas',
    '¿Qué son los créditos ECTS?',
    '¿Dónde veo notas de corte y plazas?',
    'Tengo diabetes: ¿hay plazas reservadas en ciclos o universidad?',
    'Electricidad: ¿qué opciones de FP hay?',
    '¿Qué diferencia hay entre grado oficial y título propio?',
    '¿Qué becas oficiales puedo solicitar?',
    '¿Puedo ir de FP superior a la universidad?'
  ];
  document.getElementById('questionChips').innerHTML=qs.map(q=>`<button class="question-chip" type="button">${escapeHTML(q)}</button>`).join('');
  document.querySelectorAll('.question-chip').forEach(b=>b.onclick=()=>{document.getElementById('chatInput').value=b.textContent;document.getElementById('chatForm').dispatchEvent(new Event('submit'))});
}

renderFAQ = function(){
  const q=normalise(document.getElementById('faqSearch')?.value||'');
  const list=state.data.faq.filter(x=>!q||normalise(x.q+' '+x.a).includes(q));
  document.getElementById('faqList').innerHTML=list.map(x=>`<details class="faq-item"><summary>${escapeHTML(x.q)}</summary><p>${escapeHTML(x.a)}</p>${sourceLinks(x.sources)}</details>`).join('');
}

renderAdventure = function(){
  const startOptions=[['eso_cursando','Estoy cursando ESO'],['eso_titulo','Tengo título de ESO'],['eso_sin','No tengo título de ESO'],['bach','Estoy en Bachillerato'],['fpgm','Estoy en Grado Medio'],['fpgs','Estoy en Grado Superior'],['grado','Ya tengo un grado']];
  document.getElementById('adventureStartOptions').innerHTML=startOptions.map(([id,l])=>`<button class="${state.adventure.start===id?'active':''}" data-start="${id}">${escapeHTML(l)}</button>`).join('');
  document.querySelectorAll('[data-start]').forEach(b=>b.onclick=()=>{state.adventure.start=b.dataset.start;state.adventure.step=2;renderAdventure();scrollWizard(2)});
  const priority = ['grado-medicina','grado-psicologia','grado-arquitectura','grado-derecho','cm-instalaciones-electricas-automaticas','cs-sistemas-electrotecnicos-automatizados','cm-soldadura-caldeiraria','cm-carpinteria-mueble','cs-energias-renovables','grado-ade','grado-educacion-primaria','grado-informatica'];
  const chips = priority.map(id=>state.data.studies.find(p=>p.id===id)).filter(Boolean);
  document.getElementById('adventureGoalOptions').innerHTML=chips.map(p=>`<button data-goal="${escapeHTML(p.name)}">${escapeHTML(p.name.replace('Técnico Superior en ','TS ').replace('Técnico en ','TM ').replace('Grado en ',''))}</button>`).join('');
  document.querySelectorAll('[data-goal]').forEach(b=>b.onclick=()=>{document.getElementById('adventureGoalSearch').value=b.dataset.goal;state.adventure.goalText=b.dataset.goal;const m=programs(state.adventure.goalText);if(isAmbiguous(m)){state.adventure.selectedProgramId=null;state.adventure.step=2}else{state.adventure.selectedProgramId=m[0]?.id||null;state.adventure.step=3}renderAdventure();if(state.adventure.step===3)scrollWizard(3)});
  const input=document.getElementById('adventureGoalSearch');
  input.oninput=e=>{state.adventure.goalText=e.target.value;state.adventure.selectedProgramId=null;renderAdventure()};
  input.onkeydown=e=>{if(e.key==='Enter'){e.preventDefault();const m=programs(input.value);if(m.length===1||!isAmbiguous(m)){state.adventure.selectedProgramId=m[0]?.id||null;state.adventure.step=3;renderAdventure();scrollWizard(3)}}};
  const matches=programs(state.adventure.goalText);
  const dis=document.getElementById('adventureDisambiguation');
  if(state.adventure.goalText&&isAmbiguous(matches)){
    dis.innerHTML=`<p class="warning-box small">${T('ambiguity')}</p>`+matches.slice(0,8).map(p=>`<button class="choice-card" data-pid="${p.id}">${escapeHTML(p.name)}<br><small>${escapeHTML(p.family)} · ${escapeHTML(p.level)}</small></button>`).join('');
    dis.querySelectorAll('[data-pid]').forEach(b=>b.onclick=()=>{state.adventure.selectedProgramId=b.dataset.pid;state.adventure.step=3;renderAdventure();scrollWizard(3)});
  } else dis.innerHTML='';
  document.getElementById('adventureQuestions').innerHTML=[
    ['balanced','Ruta equilibrada'],
    ['direct','Ruta más directa'],
    ['open','Mantener alternativas'],
    ['support','Necesito apoyo con materias difíciles'],
    ['near','Priorizar centros cercanos'],
    ['employment','Priorizar empleabilidad']
  ].map(([id,l])=>`<button class="${state.adventure.adjustment===id?'active':''}" data-adjust="${id}">${escapeHTML(l)}</button>`).join('');
  document.querySelectorAll('[data-adjust]').forEach(b=>b.onclick=()=>{state.adventure.adjustment=b.dataset.adjust;renderAdventureResult()});
  document.querySelectorAll('.wizard-step').forEach((el,i)=>el.classList.toggle('active',i+1===state.adventure.step));
  document.querySelectorAll('.wizard-progress span').forEach((el,i)=>el.classList.toggle('active',i+1<=state.adventure.step));
  renderAdventureResult();
}

makeRouteOptionsForStart = function(p){
  let options = p.route_options?.length ? JSON.parse(JSON.stringify(p.route_options)) : [{title:'Ruta principal',steps:p.route.split('→').map(s=>s.trim())}];
  const s=state.adventure.start;
  if(s==='eso_sin') options.unshift({title:'Vía previa si no hay título de ESO',steps:['ESO sin título','FP básica / adultos / prueba de acceso','Obtención de requisito de acceso','Siguiente etapa compatible',p.name]});
  if((s==='eso_cursando'||s==='eso_titulo') && p.type==='grado') options.unshift({title:'Ruta universitaria desde ESO',steps:['ESO','Bachillerato adecuado','Materias y ponderaciones','PAU/ABAU','Grado universitario']});
  if((s==='eso_cursando'||s==='eso_titulo') && p.type==='fpgs') options.unshift({title:'Ruta FP superior desde ESO',steps:['ESO','Bachillerato o FP grado medio','FP grado superior','FCT / proyecto','Empleo o universidad']});
  if(s==='bach' && p.type==='fpgs') options.unshift({title:'Desde Bachillerato a FP superior',steps:['Bachillerato','Solicitud admisión FP','FP superior','FCT','Empleo cualificado']});
  if(s==='bach' && p.type==='grado') options.unshift({title:'Desde Bachillerato a universidad',steps:['Bachillerato','Materias ponderables','PAU/ABAU','Admisión','Grado']});
  if(s==='fpgm') options.unshift({title:'Desde Grado Medio',steps:['FP grado medio','FP superior afín o bachillerato','Especialización','Meta']});
  if(s==='fpgs' && p.type==='grado') options.unshift({title:'Desde FP superior a universidad',steps:['FP grado superior','Admisión universitaria','Mejora de nota si conviene','Grado objetivo']});
  if(s==='grado') options.unshift({title:'Después de un grado',steps:['Grado universitario','Comprobar profesión regulada','Máster si procede','Especialización / empleo']});
  return options.slice(0,4);
}

renderAdventureResult = function(){
  const stage=document.getElementById('adventureResult');
  if(!state.adventure.start||!state.adventure.goalText){
    stage.innerHTML=`<div class="route-board"><div class="route-intro"><h2>${T('sim')}</h2><p>${T('chooseStart')} ${T('chooseGoal')}</p></div></div>`;return;
  }
  const p=selectedProgram();
  if(!p){stage.innerHTML=`<div class="route-board"><div class="route-intro"><h2>${T('sim')}</h2><p>${T('officialNote')}</p>${sourceLinks(['todofp-familias','xunta-fp-oferta','qedu','ruct'])}</div></div>`;return}
  const options=makeRouteOptionsForStart(p);
  const adjustmentText = {
    balanced:'Ruta equilibrada: combina viabilidad, continuidad y fuentes oficiales.',
    direct:'Ruta directa: se prioriza el camino más corto compatible con requisitos.',
    open:'Ruta abierta: se señalan alternativas para no cerrar opciones antes de tiempo.',
    support:'Ruta con apoyo: se recomienda no elegir solo por ponderación, sino por nota realista, base académica y refuerzo posible.',
    near:'Ruta con cercanía: comprueba centros y localidades en Xunta/QEDU antes de decidir.',
    employment:'Ruta con empleabilidad: revisa SEPE, prácticas, especialización e inserción territorial.'
  }[state.adventure.adjustment] || '';
  stage.innerHTML=`<div class="route-board" id="journeyPrintable">
    <div class="route-intro"><p class="eyebrow">${T('sim')}</p><h2>${escapeHTML(p.name)}</h2><p>${escapeHTML(p.regulated)}</p><p><strong>Ajuste:</strong> ${escapeHTML(adjustmentText)}</p></div>
    <div class="branch-grid">${options.map((opt,bi)=>`<div class="branch"><div class="branch-title">${escapeHTML(opt.title)}</div><div class="route-steps">${opt.steps.map((s,i)=>`<div class="route-node"><button type="button" data-node="${bi}-${i}"><strong>${i+1}. ${escapeHTML(s)}</strong><small>Clic para ampliar</small></button></div>`).join('')}</div></div>`).join('')}</div>
    <div class="route-info-panel" id="routeInfo"><h3>${T('important')}</h3><p>${escapeHTML(p.demand)}</p><p><strong>${T('subjects')}:</strong> ${(p.subjects||[]).map(escapeHTML).join(', ')}</p>${ponderationHTML(p)}${availabilityHTML(p)}<p class="warning-box small">${T('officialNote')}</p><div class="result-actions"><button type="button" class="button pdf-button" onclick="exportPDF('journeyPrintable','ITINERA · ${escapeHTML(p.name)}')">${T('pdf')}</button></div>${sourceLinks(p.sources)}</div>
  </div>`;
  document.querySelectorAll('[data-node]').forEach(btn=>btn.onclick=()=>{const info=document.getElementById('routeInfo');info.scrollIntoView({behavior:'smooth',block:'nearest'});info.classList.add('flash');setTimeout(()=>info.classList.remove('flash'),700)});
}

botAnswer = function(text){
  const q=normalise(text);
  if((q.includes('diabetes')||q.includes('discapacidad')||q.includes('enfermedad')||q.includes('plaza reservada')||q.includes('reservada')) && (q.includes('ciclo')||q.includes('fp')||q.includes('universidad')||q.includes('grao')||q.includes('grado'))){
    return `<p>La existencia de plazas reservadas depende del tipo de enseñanza y de la convocatoria. En universidad suele haber cupos regulados, por ejemplo para discapacidad o deportistas de alto nivel/rendimiento. En FP y ciclos debes revisar la normativa y la convocatoria autonómica concreta. Tener una enfermedad, como diabetes, no implica automáticamente plaza reservada: lo determinante suele ser la acreditación oficial de discapacidad u otra condición reconocida.</p>${sourceLinks(['rd-412-2014','boe-rd-534-2024','ciug-admision','xunta-fp-oferta'])}`;
  }
  if(q.includes('matematic')&&q.includes('psicolog')){
    return `<p>Si quieres Psicología pero las matemáticas no se te dan bien, no decidas solo por la ponderación. Compara: 1) qué materias ponderan en la CIUG, 2) qué nota realista puedes obtener, 3) qué base te aporta cada materia y 4) si puedes compensar con otra materia mejor dominada. Una materia que pondera 0,2 puede no compensar si la nota esperable es baja. Revisa también Biología y otras materias que puedan ponderar para el grado concreto.</p>${sourceLinks(['ciug-ponderaciones-2026','ciug-admision','qedu'])}`;
  }
  if(q.includes('credito')||q.includes('ects')||q.includes('asignatura')||q.includes('semestre')){
    return `<p>En la universidad, los créditos ECTS expresan carga de trabajo del estudiante. Muchos grados se organizan en 240 ECTS, normalmente repartidos en cuatro cursos, pero hay excepciones. Para saber créditos, asignaturas, prácticas, menciones y estructura debes abrir el plan oficial del grado y verificarlo en RUCT o en la universidad.</p>${sourceLinks(['rd-822-2021','ruct','qedu'])}`;
  }
  if(q.includes('nota')||q.includes('corte')||q.includes('plaza')||q.includes('admision')||q.includes('admisión')){
    return `<p>Las notas de corte cambian cada curso y son una referencia retrospectiva, no una garantía. Para Galicia debes consultar CIUG, revisar grado, universidad, convocatoria, plazas y ponderaciones. Si el acceso es competitivo, conviene simular varias combinaciones de materias.</p>${sourceLinks(['ciug-admision','ciug-notas-corte','ciug-ponderaciones-2026'])}`;
  }
  if(q.includes('beca')||q.includes('neae')||q.includes('ayuda')){
    return `<p>Las becas oficiales deben revisarse en el portal de Becas Educación y en la convocatoria concreta. Las ayudas NEAE tienen requisitos y plazos propios. ITINERA puede orientarte, pero la solicitud real debe hacerse con la convocatoria oficial vigente.</p>${sourceLinks(['becas-portada','becas-educacion-portada','beca-general','beca-neae'])}`;
  }
  if(q.includes('oficial')||q.includes('titulo propio')||q.includes('título propio')||q.includes('ruct')){
    return `<p>Para comprobar si un grado o máster es oficial, usa RUCT. QEDU sirve para explorar qué estudiar y dónde, pero la verificación administrativa del título oficial se hace en RUCT. Un título propio no sustituye a un título oficial cuando este es requisito.</p>${sourceLinks(['qedu','ruct','ruct-faq'])}`;
  }
  if(q.includes('master')||q.includes('máster')||q.includes('habilitante')||q.includes('profesion regulada')||q.includes('profesión regulada')){
    return `<p>Un máster habilitante es un máster universitario oficial necesario para ciertas profesiones reguladas. Casos frecuentes: Arquitectura, Abogacía y Procura, Psicología General Sanitaria, Profesorado de Secundaria y algunas ingenierías. Debe comprobarse el título exacto en RUCT y la normativa aplicable.</p>${sourceLinks(['ruct-faq','rd-822-2021','ruct'])}`;
  }
  if(q.includes('electricidad')||q.includes('electrica')||q.includes('eléctrica')||q.includes('electronica')||q.includes('electrónica')){
    const list=programs('electricidad','all','all').filter(p=>p.family.includes('Electricidad')||p.family.includes('Energía')).slice(0,6);
    return `<p>Electricidad puede referirse a varias opciones. Las más probables son estas. Elige según si buscas grado medio, grado superior, mantenimiento, automatización, telecomunicaciones o energía.</p>${list.map(p=>programCard(p,p.score<1.1)).join('')}`;
  }
  const p=programs(text)[0];
  if(p&&p.score>.55)return programCard(p,p.score<1.1);
  return `<p>No tengo información cerrada suficiente para responder con seguridad a esa pregunta. Te dejo las fuentes oficiales adecuadas para comprobar el dato exacto.</p>${sourceLinks(['todofp-familias','xunta-fp-oferta','xunta-fp-centros','qedu','ruct','ciug-admision','becas-portada'])}`;
}



