function accessExamCard(exam){
  return `<article class="content-card access-card"><h2>${escapeHTML(exam.title)}</h2><p>${escapeHTML(exam.short)}</p><p><strong>Cuándo se usa:</strong> ${escapeHTML(exam.when_needed)}</p><p><strong>Edad/requisito:</strong> ${escapeHTML(exam.age)}</p><h3>Partes de la prueba</h3><ul>${exam.structure.map(x=>`<li>${escapeHTML(x)}</li>`).join('')}</ul><h3>Notas importantes</h3><ul>${exam.notes.map(x=>`<li>${escapeHTML(x)}</li>`).join('')}</ul>${sourceLinks(exam.sources)}</article>`;
}

