function step(label,type='direct',info=''){
  return {label,type,info};
}
function fpFamilyOptionFor(program){
  const f=(program.family||'').toLowerCase();
  if(f.includes('electricidad')||f.includes('energía')) return 'Opción B: Debuxo técnico, Tecnoloxía industrial e Física';
  if(f.includes('sanidad')||f.includes('salud')||f.includes('química')||f.includes('agraria')) return 'Opción C: Ciencias da terra e ambientais, Química e Bioloxía';
  if(f.includes('administr')||f.includes('comerc')||f.includes('social')) return 'Opción A: Economía da empresa, Lingua estranxeira e Filosofía';
  return 'Opción específica A/B/C segundo familia profesional';
}
function validRoutesForStart(program){
  const s=state.adventure.start;
  const p=program;
  const isGS=p.type==='fpgs';
  const isGM=p.type==='fpgm';
  const isDegree=p.type==='grado';
  const isMaster=p.type==='master';
  const routes=[];
  if(s==='eso_sin'){
    if(isGM){
      routes.push({title:'Vía con prueba a grado medio',steps:[
        step('ESO sin título','start','Punto de partida.'),
        step('Prueba acceso GM','exam','Parte sociolingüística, parte matemática y parte científico-técnica.'),
        step(p.name,'direct','Acceso a grado medio si se supera la prueba y se obtiene plaza.'),
        step('FCT / titulación','direct','Formación en centros de trabajo y titulación.')
      ]});
    } else if(isGS){
      routes.push({title:'No hay salto directo: vía por grado medio',steps:[
        step('ESO sin título','start','Punto de partida.'),
        step('Prueba acceso GM','exam','Primero se necesita acceder a grado medio o cumplir un requisito equivalente.'),
        step('FP grado medio','direct','Preferentemente de familia afín si la oferta y admisión lo permiten.'),
        step(p.name,'direct','Acceso a grado superior desde FP de grado medio o vía establecida.'),
        step('Meta','direct','Empleo cualificado o continuidad.')
      ]});
      routes.push({title:'No hay salto directo: vía por prueba a grado superior',steps:[
        step('ESO sin título','start','Punto de partida.'),
        step('Preparación requisito/edad','exam','Para GS la prueba exige requisitos de edad y opción específica.'),
        step('Prueba acceso GS','exam',fpFamilyOptionFor(p)),
        step(p.name,'direct','Acceso condicionado a superación, admisión y plazas.')
      ]});
    } else {
      routes.push({title:'Regularizar acceso antes de la ruta universitaria',steps:[
        step('ESO sin título','start','Primero hay que obtener requisito académico o vía equivalente.'),
        step('ESO adultos / FP básica / prueba','exam','Consultar opción real según edad y convocatoria.'),
        step('Bachillerato o FP','direct','Elegir vía compatible con la meta.'),
        step(p.name,'direct','Llegada a la meta cuando se cumplan requisitos.')
      ]});
    }
  } else if(s==='eso_cursando'||s==='eso_titulo'){
    if(isGM){
      routes.push({title:'Ruta directa a grado medio',steps:[
        step('ESO','start','Con título de ESO o requisito equivalente.'),
        step(p.name,'direct','Ciclo formativo de grado medio.'),
        step('FCT','direct','Prácticas y módulos del ciclo.'),
        step('Empleo o continuidad','direct','Posible continuidad a FP superior.')
      ]});
    } else if(isGS){
      routes.push({title:'Vía por Bachillerato',steps:[
        step('ESO','start','Desde ESO no se accede directamente a un ciclo superior.'),
        step('Bachillerato','direct','Vía académica ordinaria hacia GS o universidad.'),
        step(p.name,'direct','Acceso a FP grado superior si se cumplen requisitos y admisión.'),
        step('FCT / titulación','direct','Finalización del ciclo.')
      ]});
      routes.push({title:'Vía por FP grado medio',steps:[
        step('ESO','start','Punto de partida.'),
        step('FP grado medio','direct','Preferentemente familia afín si se desea continuidad técnica.'),
        step(p.name,'direct','Acceso a grado superior desde grado medio, sujeto a admisión.'),
        step('Empleo o universidad','direct','Continuidad posterior.')
      ]});
      routes.push({title:'Vía excepcional con prueba de acceso',steps:[
        step('ESO','start','No hay salto directo ordinario.'),
        step('Requisito de edad','exam','Para prueba de GS, revisar edad y convocatoria vigente.'),
        step('Prueba acceso GS','exam',fpFamilyOptionFor(p)),
        step(p.name,'direct','Acceso condicionado a superación y plazas.')
      ]});
    } else if(isDegree){
      routes.push({title:'Ruta universitaria ordinaria',steps:[
        step('ESO','start','Punto de partida.'),
        step('Bachillerato adecuado','direct','Escoger modalidad coherente con el grado.'),
        step('Materias ponderables','exam','No es una prueba de acceso FP: es un punto crítico. Revisar CIUG.'),
        step('PAU/ABAU','exam','Acceso universitario y fase de admisión.'),
        step(p.name,'direct','Admisión si la nota es suficiente.')
      ]});
      routes.push({title:'Ruta alternativa por FP superior',steps:[
        step('ESO','start','Punto de partida.'),
        step('FP grado medio','direct','Vía profesional inicial.'),
        step('FP grado superior','direct','Permite acceso a universidad.'),
        step('Admisión universitaria','exam','Puede requerir mejorar nota según grado.'),
        step(p.name,'direct','Grado universitario.')
      ]});
    }
  } else if(s==='bach'){
    if(isGS){
      routes.push({title:'Desde Bachillerato a grado superior',steps:[
        step('Bachillerato','start','Requisito ordinario de acceso.'),
        step(p.name,'direct','Ciclo superior.'),
        step('FCT / titulación','direct','Finalización y salida profesional.')
      ]});
    } else if(isDegree){
      routes.push({title:'Desde Bachillerato a universidad',steps:[
        step('Bachillerato','start','Revisar modalidad y materias.'),
        step('Materias ponderables','exam','Punto crítico: escoger materias que ponderen y se puedan aprobar con buena nota.'),
        step('PAU/ABAU','exam','Prueba de acceso/admisión universitaria.'),
        step(p.name,'direct','Admisión si la nota alcanza la referencia del grado.')
      ]});
    } else if(isGM){
      routes.push({title:'Bachillerato también permite ir a FP de grado medio',steps:[step('Bachillerato','start','Tienes un requisito superior.'),step(p.name,'direct','Puedes solicitar FP de grado medio según admisión.'),step('Empleo o continuidad','direct','Posible continuidad posterior.')]});
    }
  } else if(s==='fpgm'){
    if(isGS){
      routes.push({title:'Continuidad natural desde grado medio',steps:[step('FP grado medio','start','Punto de partida.'),step('Admisión a GS','exam','No es automático: revisar plazas, criterios y familia.'),step(p.name,'direct','Ciclo superior.'),step('Empleo o universidad','direct','Salida posterior.')]});
    } else if(isDegree){
      routes.push({title:'Vía por FP superior antes de universidad',steps:[step('FP grado medio','start','Punto de partida.'),step('FP grado superior','direct','Paso intermedio habitual.'),step('Admisión universitaria','exam','Mejora de nota si hace falta.'),step(p.name,'direct','Grado universitario.')]});
    } else routes.push({title:'Especialización o continuidad',steps:[step('FP grado medio','start','Punto de partida.'),step(p.name,'direct','Meta seleccionada.')]});
  } else if(s==='fpgs'){
    if(isDegree){
      routes.push({title:'Desde FP superior a universidad',steps:[step('FP grado superior','start','Vía de acceso a universidad.'),step('Admisión universitaria','exam','Revisar cupos, nota y posible mejora con materias.'),step(p.name,'direct','Grado universitario.')]});
    } else routes.push({title:'Continuidad desde FP superior',steps:[step('FP grado superior','start','Punto de partida.'),step(p.name,'direct','Meta seleccionada.')]});
  } else if(s==='grado'){
    routes.push({title:'Después de un grado',steps:[step('Grado universitario','start','Punto de partida.'),step('Comprobar profesión regulada','exam','Revisar si requiere máster habilitante.'),step(isMaster?p.name:'Máster/especialización si procede','direct','Formación posterior.'),step('Meta profesional','direct','Ejercicio o especialización.')]});
  }
  if(!routes.length){
    routes.push({title:'Ruta orientativa',steps:(p.route_options?.[0]?.steps||p.route.split('→')).map((x,i)=>step(String(x).trim(),i===0?'start':'direct','Revisar requisitos oficiales.'))});
  }
  return routes;
}
makeRouteOptionsForStart = function(p){ return validRoutesForStart(p); };

renderAdventureResult = function(){
  const stage=document.getElementById('adventureResult');
  if(!state.adventure.start||!state.adventure.goalText){
    stage.innerHTML=`<div class="route-board"><div class="route-intro"><h2>${T('sim')}</h2><p>${T('chooseStart')} ${T('chooseGoal')}</p></div></div>`;return;
  }
  const p=selectedProgram();
  if(!p){stage.innerHTML=`<div class="route-board"><div class="route-intro"><h2>${T('sim')}</h2><p>${T('officialNote')}</p>${sourceLinks(['todofp-familias','xunta-fp-oferta','qedu','ruct'])}</div></div>`;return}
  const options=validRoutesForStart(p);
  const adjustmentText = {
    balanced:'Ruta equilibrada: combina viabilidad, continuidad y fuentes oficiales.',
    direct:'Ruta directa: se prioriza el camino más corto compatible con requisitos, sin inventar saltos que no existen.',
    open:'Ruta abierta: se muestran bifurcaciones para mantener alternativas académicas.',
    support:'Ruta con apoyo: no decide solo por ponderación, sino por nota realista, base académica y apoyos posibles.',
    near:'Ruta con cercanía: comprueba centros y localidades en Xunta/QEDU antes de decidir.',
    employment:'Ruta con empleabilidad: revisa SEPE, prácticas, especialización e inserción territorial.'
  }[state.adventure.adjustment] || '';
  stage.innerHTML=`<div class="route-board" id="journeyPrintable">
    <div class="route-intro"><p class="eyebrow">${T('sim')}</p><h2>${escapeHTML(p.name)}</h2><p>${escapeHTML(p.regulated)}</p><p><strong>Ajuste:</strong> ${escapeHTML(adjustmentText)}</p></div>
    <div class="branch-grid">${options.map((opt,bi)=>`<div class="branch"><div class="branch-title">${escapeHTML(opt.title)}</div><div class="route-steps route-steps-v010">${opt.steps.map((st,i)=>`<div class="route-node ${st.type==='exam'?'exam-node blink-node':st.type==='start'?'start-node':'direct-node'}"><button type="button" data-node="${bi}-${i}" data-info="${escapeHTML(st.info||'')}"><strong>${i+1}. ${escapeHTML(st.label||st)}</strong><small>${st.type==='exam'?T('examCheckpoint'):T('directConnection')}</small></button></div>`).join('')}</div></div>`).join('')}</div>
    <div class="route-info-panel" id="routeInfo"><h3>${T('important')}</h3><p id="nodeInfoText">${escapeHTML(p.demand)}</p><p><strong>${T('subjects')}:</strong> ${(p.subjects||[]).map(escapeHTML).join(', ')}</p>${ponderationHTML(p)}${availabilityHTML(p)}<p class="warning-box small">${T('officialNote')}</p><div class="result-actions"><button type="button" class="button pdf-button" onclick="exportPDF('journeyPrintable','ITINERA · ${escapeHTML(p.name)}')">${T('pdf')}</button></div>${sourceLinks(p.sources)}</div>
  </div>`;
  document.querySelectorAll('[data-node]').forEach(btn=>btn.onclick=()=>{const info=document.getElementById('routeInfo');const txt=document.getElementById('nodeInfoText');if(txt)txt.textContent=btn.dataset.info||p.demand;info.scrollIntoView({behavior:'smooth',block:'nearest'});info.classList.add('flash');setTimeout(()=>info.classList.remove('flash'),700)});
};

botAnswer = function(text){
  const q=normalise(text);
  if(q.includes('ciclo superior')&&q.includes('eso')){
    return `<p>No se debe representar como salto directo de ESO a ciclo superior. Desde ESO hay que pasar por Bachillerato o por FP de grado medio, o cumplir otra vía válida. Si no se cumple requisito, puede existir prueba de acceso a grado superior, con parte común y parte específica.</p>${sourceLinks(['xunta-proba-gs-info-2026','xunta-proba-gs-xeral','todofp'])}`;
  }
  if(q.includes('prueba')||q.includes('proba')||q.includes('acceso grado superior')||q.includes('acceso grao superior')){
    return `<p>En Galicia, la prueba de acceso a grado superior se dirige a quienes no cumplen requisitos ordinarios. La información general indica parte común (Lingua galega, Lingua castelá y Matemáticas) y parte específica con opciones A, B o C según familias profesionales. Para Electricidad y Electrónica suele interesar revisar la opción B, pero hay que comprobar la familia exacta en la convocatoria.</p>${sourceLinks(['xunta-proba-gs-info-2026','xunta-proba-gs-xeral','xunta-exames-probas'])}`;
  }
  if(q.includes('grado medio')&&q.includes('prueba')||q.includes('grao medio')&&q.includes('proba')){
    return `<p>La prueba de acceso a grado medio en Galicia se organiza en parte sociolingüística, parte matemática y parte científico-técnica. La superación permite acceder a ciclos de grado medio en las condiciones de admisión que se establezcan.</p>${sourceLinks(['xunta-proba-gm-info-2026','xunta-probas','xunta-exames-probas'])}`;
  }
  if(q.includes('ia')||q.includes('chatbot abierto')||q.includes('inteligencia artificial')||q.includes('rag')){
    return `<p>Sí, puede implementarse un ItineraBot con IA documental. La regla debe ser estricta: responder solo con documentos oficiales incorporados, citar fuente y reconocer límites cuando no haya información suficiente. Técnicamente requiere backend, clave API, base documental y recuperación semántica.</p>${sourceLinks(['openai-responses','openai-vector-stores','ruct','todofp','xunta-fp-oferta','ciug-admision'])}`;
  }
  if((q.includes('diabetes')||q.includes('discapacidad')||q.includes('enfermedad')||q.includes('plaza reservada')||q.includes('reservada')) && (q.includes('ciclo')||q.includes('fp')||q.includes('universidad')||q.includes('grao')||q.includes('grado'))){
    return `<p>La existencia de plazas reservadas depende del tipo de enseñanza y de la convocatoria. En universidad suele haber cupos regulados, por ejemplo para discapacidad o deportistas de alto nivel/rendimiento. En FP y ciclos debes revisar la normativa y la convocatoria autonómica concreta. Tener una enfermedad, como diabetes, no implica automáticamente plaza reservada: lo determinante suele ser la acreditación oficial de discapacidad u otra condición reconocida.</p>${sourceLinks(['rd-412-2014','boe-rd-534-2024','ciug-admision','xunta-fp-oferta'])}`;
  }
  if(q.includes('matematic')&&q.includes('psicolog')){
    return `<p>Si quieres Psicología pero las matemáticas no se te dan bien, no decidas solo por la ponderación. Compara: 1) qué materias ponderan en la CIUG, 2) qué nota realista puedes obtener, 3) qué base te aporta cada materia y 4) si puedes compensar con otra materia mejor dominada. Una materia que pondera 0,2 puede no compensar si la nota esperable es baja.</p>${sourceLinks(['ciug-ponderaciones-2026','ciug-admision','qedu'])}`;
  }
  if(q.includes('nota')||q.includes('corte')||q.includes('plaza')||q.includes('admision')||q.includes('admisión')){
    return `<p>Las notas de corte cambian cada curso y son una referencia retrospectiva, no una garantía. Para Galicia debes consultar CIUG, revisar grado, universidad, convocatoria, plazas y ponderaciones.</p>${sourceLinks(['ciug-admision','ciug-notas-corte','ciug-ponderaciones-2026'])}`;
  }
  const p=programs(text)[0];
  if(p&&p.score>.55)return programCard(p,p.score<1.1);
  return `<p>No tengo información cerrada suficiente para responder con seguridad a esa pregunta. Te dejo las fuentes oficiales adecuadas para comprobar el dato exacto.</p>${sourceLinks(['todofp-familias','xunta-fp-oferta','xunta-fp-centros','qedu','ruct','ciug-admision','becas-portada'])}`;
};

async function askItineraBot(text){
  try{
    const res=await fetch('/.netlify/functions/itinerabot-rag',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({question:text, lang:state.lang})});
    if(res.ok){
      const data=await res.json();
      if(data?.answer) return `<p>${escapeHTML(data.answer)}</p>${(data.sources||[]).map(s=>`<a class="source-link" target="_blank" rel="noopener noreferrer" href="${s.url}"><strong>${escapeHTML(s.title||s.url)}</strong><span>${escapeHTML(s.use||'Fonte oficial')}</span></a>`).join('')}`;
    }
  }catch(e){}
  return botAnswer(text);
}

init = function(){
  renderBasics();renderHeadings();renderSelects();renderHomeCards();renderStaticSections();renderTags();renderAdventure();renderQuestionChips();bindRoutes();resetChat();
  document.getElementById('studySearchBtn').onclick=runSearch;
  document.getElementById('studySearch').onkeydown=e=>{if(e.key==='Enter')runSearch()};
  document.getElementById('faqSearch').oninput=renderFAQ;
  document.getElementById('languageSelect').onchange=e=>{state.lang=e.target.value;localStorage.setItem('itineraLang',state.lang);renderBasics();renderSelects();renderHeadings();renderHomeCards();renderStaticSections();renderQuestionChips();resetChat()};
  document.getElementById('fontSelect').onchange=e=>{state.font=e.target.value;localStorage.setItem('itineraFont',state.font);renderBasics()};
  document.getElementById('chatForm').onsubmit=async e=>{e.preventDefault();const input=document.getElementById('chatInput');const txt=input.value.trim();if(!txt)return;addMsg('user',`<p>${escapeHTML(txt)}</p>`);input.value='';addMsg('bot','<p>Consultando ItineraBot…</p>');const log=document.getElementById('chatLog');const pending=log.lastElementChild;pending.innerHTML=await askItineraBot(txt);log.scrollTop=log.scrollHeight};
  document.getElementById('navToggle').onclick=()=>document.getElementById('mainNav').classList.toggle('open');
  document.getElementById('adventurePdfBtn').onclick=()=>exportPDF('adventureResult','ITINERA · Simula tu itinerario');
  document.querySelectorAll('[data-modal-open]').forEach(b=>b.onclick=()=>openModal(b.dataset.modalOpen));
  document.querySelectorAll('[data-modal-close]').forEach(b=>b.onclick=closeModal);
  document.getElementById('modalBackdrop').onclick=closeModal;
  routeTo(location.hash.replace('#','')||'inicio');
};



