function groupedOfficialMenu(){
  const menu=document.querySelector('.official-menu');
  if(!menu || menu.dataset.grouped==='1') return;
  const items=[...menu.querySelectorAll('a')];
  const byId=id=>items.find(a=>a.id===id);
  const groups=[
    ['Orientación general',['navItinerarios','navBach','navPonderaciones']],
    ['Estudios y oferta',['navEstudios','navFP','navUniversidad']],
    ['Acceso, ayudas y cambios',['navPruebas','navBecas','navCupos','navConvalidaciones']]
  ];
  menu.innerHTML=groups.map(([title,ids])=>`<div class="menu-group"><p>${escapeHTML(title)}</p>${ids.map(id=>byId(id)?.outerHTML||'').join('')}</div>`).join('');
  menu.dataset.grouped='1';
}

function accessExamVisualCard(exam){
  const accessType = exam.id.includes('superior') ? 'GS' : 'GM';
  return `<article class="access-visual-card">
    <div class="access-badge">${accessType}</div>
    <div>
      <h2>${escapeHTML(exam.title)}</h2>
      <p>${escapeHTML(exam.short)}</p>
      <div class="access-mini-flow">
        <span>Requisito</span><i></i><span>Inscrición</span><i></i><span>Proba</span><i></i><span>Admisión</span>
      </div>
      <div class="result-actions">
        <button type="button" class="button primary" onclick="openAccessModal('${exam.id}')">${T('accessDetails')}</button>
        <button type="button" class="button pdf-button" onclick="exportPDFPremiumFromHTML('ITINERA · ${escapeHTML(exam.title)}', accessExamDetailHTMLById('${exam.id}'))">${T('pdf')}</button>
      </div>
    </div>
  </article>`;
}
function accessExamDetailHTMLById(id){
  const exam=(state.data.access_exams||[]).find(x=>x.id===id);
  if(!exam) return '';
  return `<article class="access-detail">
    <h2>${escapeHTML(exam.title)}</h2>
    <p>${escapeHTML(exam.short)}</p>
    <section><h3>Cuándo se usa</h3><p>${escapeHTML(exam.when_needed)}</p></section>
    <section><h3>Edad/requisito</h3><p>${escapeHTML(exam.age)}</p></section>
    <section><h3>${T('accessParts')}</h3><ul>${exam.structure.map(x=>`<li>${escapeHTML(x)}</li>`).join('')}</ul></section>
    <section><h3>${T('accessNotes')}</h3><ul>${exam.notes.map(x=>`<li>${escapeHTML(x)}</li>`).join('')}</ul></section>
    ${sourceLinks(exam.sources)}
  </article>`;
}
function openAccessModal(id){
  const exam=(state.data.access_exams||[]).find(x=>x.id===id);
  openDetailModal(exam?.title||T('accessTitle'), accessExamDetailHTMLById(id));
}

function groupedStudiesHTML(list){
  const byType = {};
  list.forEach(p=>{
    const typeLabel = p.type==='fpgm'?'FP · Grado medio':p.type==='fpgs'?'FP · Grado superior':p.type==='grado'?'Universidad · Grado':p.type==='master'?'Universidad · Máster':'Otros estudios';
    byType[typeLabel] ||= {};
    byType[typeLabel][p.family] ||= [];
    byType[typeLabel][p.family].push(p);
  });
  return Object.entries(byType).map(([type,families])=>`<section class="studies-group"><h2>${escapeHTML(type)}</h2>${Object.entries(families).map(([fam,items])=>`<details open class="family-group"><summary>${escapeHTML(fam)} <span>${items.length}</span></summary><div class="family-study-grid">${items.map(p=>`<button class="study-list-item" type="button" onclick="showStudySheet('${p.id}')"><strong>${escapeHTML(p.name)}</strong><span>${escapeHTML(p.level)} · ${escapeHTML(p.family)}</span></button>`).join('')}</div></details>`).join('')}</section>`).join('');
}
renderStudiesBrowser = function(){
  const search=document.getElementById('allStudiesSearch');
  const type=document.getElementById('allStudiesType');
  const family=document.getElementById('allStudiesFamily');
  const btn=document.getElementById('allStudiesSearchBtn');
  if(!search||!type||!family) return;
  const types=[['all',T('allTypes')],['fpgm','FP grado medio'],['fpgs','FP grado superior'],['grado','Grado universitario'],['master','Máster']];
  type.innerHTML=types.map(([v,l])=>`<option value="${v}">${escapeHTML(l)}</option>`).join('');
  const families=[...new Set(state.data.studies.map(p=>p.family))].sort();
  family.innerHTML=`<option value="all">${T('allFamilies')}</option>`+families.map(f=>`<option value="${escapeHTML(f)}">${escapeHTML(f)}</option>`).join('');
  if(btn) btn.textContent=T('searchMatches');
  const draw=()=>{
    const q=search.value.trim();
    const list = q ? programs(q,type.value,family.value).slice(0,80) : state.data.studies.filter(p=>(type.value==='all'||p.type===type.value)&&(family.value==='all'||p.family===family.value)).sort((a,b)=>a.type.localeCompare(b.type)||a.family.localeCompare(b.family)||a.name.localeCompare(b.name));
    document.getElementById('allStudiesList').innerHTML=groupedStudiesHTML(list);
  };
  if(btn) btn.onclick=draw;
  search.onkeydown=e=>{if(e.key==='Enter') draw()};
  type.onchange=draw; family.onchange=draw; draw();
};

function faqCategory(item){
  const q=normalise(item.q+' '+item.a);
  if(q.includes('beca')||q.includes('neae')) return 'Becas e axudas';
  if(q.includes('cupo')||q.includes('discapacidad')||q.includes('deportista')||q.includes('reservada')) return 'Cupos e situacións específicas';
  if(q.includes('credito')||q.includes('ects')||q.includes('ruct')||q.includes('titulo')||q.includes('universidad')||q.includes('grado')||q.includes('master')) return 'Universidade, créditos e títulos';
  if(q.includes('fp')||q.includes('ciclo')||q.includes('convalid')||q.includes('modulo')) return 'Formación Profesional e convalidacións';
  if(q.includes('prueba')||q.includes('proba')||q.includes('acceso')) return 'Acceso e probas';
  return 'Orientación xeral';
}
renderFAQ = function(){
  const q=normalise(document.getElementById('faqSearch')?.value||'');
  const list=state.data.faq.filter(x=>!q||normalise(x.q+' '+x.a).includes(q));
  const grouped={};
  list.forEach(item=>{const c=faqCategory(item); grouped[c] ||= []; grouped[c].push(item);});
  document.getElementById('faqList').innerHTML=Object.entries(grouped).map(([cat,items])=>`<section class="faq-group"><h2>${escapeHTML(cat)}</h2>${items.map(x=>`<details class="faq-item"><summary>${escapeHTML(x.q)}</summary><p>${escapeHTML(x.a)}</p>${sourceLinks(x.sources)}</details>`).join('')}</section>`).join('');
};

function convalidationCard(item){
  return `<article class="content-card conv-card"><h2>${escapeHTML(item.title)}</h2><p>${escapeHTML(item.summary)}</p><button type="button" class="button primary" onclick="openDetailModal('${escapeHTML(item.title)}', convalidationDetailHTML('${item.id}'))">${T('accessDetails')}</button>${sourceLinks(item.sources)}</article>`;
}
function convalidationDetailHTML(id){
  const item=(state.data.convalidations||[]).find(x=>x.id===id);
  if(!item) return '';
  return `<article class="study-sheet"><header class="sheet-head"><h2>${escapeHTML(item.title)}</h2></header><section><p>${escapeHTML(item.summary)}</p><ul>${(item.details||[]).map(x=>`<li>${escapeHTML(x)}</li>`).join('')}</ul></section><p class="warning-box small">${T('officialNote')}</p>${sourceLinks(item.sources)}</article>`;
}

