/* ITINERA v0.15 · Supabase catalog mode */
async function loadCatalogStatus(){
  const badge = document.getElementById('updateBadge');
  if(!badge) return;
  try{
    const res = await fetch('/.netlify/functions/catalog-status');
    if(!res.ok) return;
    const data = await res.json();
    if(data?.ok && data?.totals){
      badge.textContent = `${T('update')}: ${formatDateTime(state.data.last_updated_at||LAST_UPDATED_AT)} · ${data.totals.studies} estudos en catálogo`;
      badge.title = `Supabase activo · ${data.totals.sources} fontes · ${data.totals.documents} documentos oficiais`;
    }
  }catch(e){}
}

init = (function(previousInit){
  return function(){
    previousInit();
    loadCatalogStatus();
  };
})(init);



/* ITINERA v0.16 · GitHub Pages + Supabase directo con anon key */
const ITINERA_SUPABASE = window.ITINERA_CONFIG || {};

function supabaseReady(){
  return Boolean(ITINERA_SUPABASE.SUPABASE_URL && ITINERA_SUPABASE.SUPABASE_ANON_KEY);
}
function supabaseBase(){
  return String(ITINERA_SUPABASE.SUPABASE_URL || '').replace(/\/+$/,'');
}
function supabaseHeaders(){
  return {
    apikey: ITINERA_SUPABASE.SUPABASE_ANON_KEY,
    Authorization: `Bearer ${ITINERA_SUPABASE.SUPABASE_ANON_KEY}`,
    'Content-Type': 'application/json'
  };
}
async function sbFetch(path, options={}){
  if(!supabaseReady()) throw new Error('Supabase public config missing');
  const res = await fetch(`${supabaseBase()}${path}`, {
    ...options,
    headers: {...supabaseHeaders(), ...(options.headers||{})}
  });
  if(!res.ok) throw new Error(`Supabase ${res.status}: ${await res.text().catch(()=> '')}`);
  return await res.json();
}
function mapSourceRow(row){
  return {
    id: row.id,
    title: row.title,
    url: row.url,
    category: row.category || 'general',
    use: row.usefulness || row.use || '',
    jurisdiction: row.jurisdiction || ''
  };
}
function mapStudyRow(row){
  return {
    id: row.id,
    name: row.name,
    type: row.type,
    level: row.level,
    family: row.family || 'Sin familia',
    branch: row.branch || '',
    keywords: row.keywords || [],
    route: row.route || '',
    regulated: row.regulated || '',
    demand: row.demand || '',
    labour: row.labour || '',
    subjects: Array.isArray(row.subjects) ? row.subjects : [],
    ponderation_subjects: Array.isArray(row.ponderation_subjects) ? row.ponderation_subjects : [],
    route_options: Array.isArray(row.route_options) ? row.route_options : [],
    availability_by_province: row.availability_by_province || {},
    sources: Array.isArray(row.sources) ? row.sources : [],
    source_url: row.source_url || '',
    data_quality: row.data_quality || '',
    score: row.score || 0.5,
    data_source: 'supabase'
  };
}
function mergeById(localRows=[], remoteRows=[]){
  const map = new Map();
  localRows.forEach(x => map.set(x.id, x));
  remoteRows.forEach(x => map.set(x.id, {...(map.get(x.id)||{}), ...x}));
  return [...map.values()];
}

async function supabaseSearchStudies(q='', type='all', family='all', limit=80){
  if(!supabaseReady()) return [];
  const payload = { q, study_type:type, study_family:family, max_results:limit };
  const rows = await sbFetch('/rest/v1/rpc/itinera_search_studies', {
    method:'POST',
    body: JSON.stringify(payload)
  });
  return (rows || []).map(mapStudyRow);
}

async function loadSupabaseCatalog(){
  if(!supabaseReady()){
    state.sourceMode = 'seed-local';
    return false;
  }
  try{
    const [studies, sources, faq, access, scholarships, reservations, convalidations] = await Promise.all([
      sbFetch('/rest/v1/itinera_studies?select=*&order=name.asc&limit=10000'),
      sbFetch('/rest/v1/itinera_sources?select=*&order=category.asc,title.asc&limit=1000'),
      sbFetch('/rest/v1/itinera_faq_items?select=*&order=priority.asc&limit=1000').catch(()=>[]),
      sbFetch('/rest/v1/itinera_access_exams?select=*&order=title.asc&limit=100').catch(()=>[]),
      sbFetch('/rest/v1/itinera_scholarships?select=*&order=title.asc&limit=100').catch(()=>[]),
      sbFetch('/rest/v1/itinera_reservations?select=*&order=title.asc&limit=100').catch(()=>[]),
      sbFetch('/rest/v1/itinera_convalidations?select=*&order=title.asc&limit=100').catch(()=>[])
    ]);

    const remoteStudies = (studies||[]).map(mapStudyRow);
    if(remoteStudies.length) state.data.studies = mergeById(state.data.studies || [], remoteStudies);
    if(sources?.length) state.data.official_sources = mergeById(state.data.official_sources || [], sources.map(mapSourceRow));

    if(faq?.length){
      const mapped = faq.map(x => ({q:x.question, a:x.answer, sources:x.sources || [], category:x.category || 'Orientación general'}));
      state.data.faq = mergeById(
        (state.data.faq || []).map((x,i)=>({id:`seed-faq-${i}`,...x})),
        mapped.map((x,i)=>({id:`supabase-faq-${normalise(x.q).slice(0,80)||i}`,...x}))
      );
    }
    if(access?.length) state.data.access_exams = access.map(x => ({id:x.id,title:x.title,short:x.short,when_needed:x.when_needed,age:x.age,structure:x.structure||[],notes:x.notes||[],sources:x.sources||[]}));
    if(scholarships?.length) state.data.scholarships = scholarships.map(x => ({id:x.id,title:x.title,summary:x.summary,period:x.period,sources:x.sources||[]}));
    if(reservations?.length) state.data.reservations = reservations.map(x => ({id:x.id,title:x.title,summary:x.summary,sources:x.sources||[]}));
    if(convalidations?.length) state.data.convalidations = convalidations.map(x => ({id:x.id,title:x.title,summary:x.summary,details:x.details||[],sources:x.sources||[]}));

    state.sourceMode = 'supabase';
    state.supabaseLoadedAt = new Date().toISOString();
    const badge = document.getElementById('updateBadge');
    if(badge) {
      badge.textContent = `${T('update')}: ${formatDateTime(state.data.last_updated_at||LAST_UPDATED_AT)} · Supabase: ${remoteStudies.length} estudos`;
      badge.title = `Catálogo conectado a Supabase con clave pública anon.`;
    }
    return true;
  }catch(error){
    console.warn('ITINERA Supabase fallback:', error);
    state.sourceMode = 'seed-fallback';
    const badge = document.getElementById('updateBadge');
    if(badge) badge.title = 'Supabase no respondió. ITINERA usa la base local de respaldo.';
    return false;
  }
}

programs = function(q='',type='all',family='all'){
  return state.data.studies.map(p=>{
    let score=scoreProgram(p,q);
    if(type!=='all'&&p.type!==type)score-=.55;
    if(family!=='all'&&normalise(p.family)!==normalise(family))score-=.35;
    if(!q&&(type!=='all'||family!=='all'))score+=.4;
    return{...p,score}
  }).filter(p=> q ? p.score>.30 : p.score>.01).sort((a,b)=>b.score-a.score || a.name.localeCompare(b.name)).slice(0,120)
};

runSearch = async function(){
  const q=document.getElementById('studySearch').value.trim();
  const type=document.getElementById('studyTypeFilter').value;
  const family=document.getElementById('familyFilter').value;
  const out=document.getElementById('studyResults');
  if(!q&&type==='all'&&family==='all'){
    out.innerHTML=`<div class="warning-box">${T('finderDescription')}</div>`;
    return;
  }
  out.innerHTML='<div class="result-card"><p>Buscando…</p></div>';
  let list=[];
  try{
    list = await supabaseSearchStudies(q,type,family,80);
  }catch(e){}
  if(!list.length) list = programs(q,type,family);

  if(!list.length){
    out.innerHTML=`<article class="result-card"><h3>${escapeHTML(T('finderTitle'))}</h3><p>${escapeHTML(T('officialNote'))}</p>${sourceLinks(['todofp-familias','xunta-fp-oferta','xunta-fp-centros','qedu','ruct','ciug-admision'])}</article>`;
    return;
  }
  const exact=q&&list.some(p=>normalise(p.name).includes(normalise(q))||(p.keywords||[]).some(k=>normalise(k)===normalise(q)));
  out.innerHTML=(q&&!exact?`<p class="warning-box">${T('maybe')}</p>`:'')+list.map(p=>programCard(p,q&&!normalise(p.name).includes(normalise(q)))).join('');
};

function renderStudiesBrowserV16(){
  const search=document.getElementById('allStudiesSearch');
  const type=document.getElementById('allStudiesType');
  const family=document.getElementById('allStudiesFamily');
  const btn=document.getElementById('allStudiesSearchBtn');
  if(!search||!type||!family) return;
  const types=[['all',T('allTypes')],['fpgm','FP grado medio'],['fpgs','FP grado superior'],['grado','Grado universitario'],['master','Máster']];
  type.innerHTML=types.map(([v,l])=>`<option value="${v}">${escapeHTML(l)}</option>`).join('');
  const families=[...new Set(state.data.studies.map(p=>p.family).filter(Boolean))].sort();
  family.innerHTML=`<option value="all">${T('allFamilies')}</option>`+families.map(f=>`<option value="${escapeHTML(f)}">${escapeHTML(f)}</option>`).join('');
  if(btn) btn.textContent=T('searchMatches') || 'Buscar coincidencias';
  const draw=async ()=>{
    const q=search.value.trim();
    let list=[];
    try{ if(q || type.value!=='all' || family.value!=='all') list = await supabaseSearchStudies(q,type.value,family.value,120); }catch(e){}
    if(!list.length){
      list = q ? programs(q,type.value,family.value).slice(0,120) : state.data.studies.filter(p=>(type.value==='all'||p.type===type.value)&&(family.value==='all'||p.family===family.value)).sort((a,b)=>a.type.localeCompare(b.type)||String(a.family).localeCompare(String(b.family))||a.name.localeCompare(b.name));
    }
    document.getElementById('allStudiesList').innerHTML=groupedStudiesHTML(list);
  };
  if(btn) btn.onclick=draw;
  search.onkeydown=e=>{if(e.key==='Enter') draw()};
  search.oninput=()=>{ if(search.value.trim().length>=3) draw(); };
  type.onchange=draw; family.onchange=draw; draw();
}
renderStudiesBrowser = renderStudiesBrowserV16;

studySuggestionList = function(query){
  const q=String(query||'').trim();
  if(q.length<3) return [];
  return programs(q,'all','all').slice(0,14);
};

async function refreshAfterSupabaseLoad(){
  renderBasics();
  renderSelects();
  renderStaticSections();
  renderTags();
  renderAdventure();
  renderQuestionChips();
  renderStudiesBrowser();
}

init = (function(previousInit){
  return async function(){
    previousInit();
    await loadSupabaseCatalog();
    await refreshAfterSupabaseLoad();
  }
})(init);


/* ITINERA v0.17 · ItineraBot Edge + catalog status */
botSourcesHTML = function(sources=[]){
  if(!Array.isArray(sources)||!sources.length) return '';
  return `<div class="bot-source-list">${sources.slice(0,8).map(s=>`<a class="source-link" target="_blank" rel="noopener noreferrer" href="${escapeHTML(s.url||'#')}"><strong>${escapeHTML(s.title||s.id||'Fonte oficial')}</strong><span>${escapeHTML(s.usefulness||s.use||s.category||'Fonte oficial')}</span></a>`).join('')}</div>`;
}
function formatBotPlainText(text=''){
  return String(text).split(/\n{2,}/).map(p=>`<p>${escapeHTML(p).replace(/\n/g,'<br>')}</p>`).join('');
}
askItineraBot = async function(text){
  const endpoint = window.ITINERA_CONFIG?.ITINERABOT_ENDPOINT || '';
  if(endpoint){
    try{
      const res = await fetch(endpoint, {
        method:'POST',
        headers:{
          'content-type':'application/json',
          'apikey': window.ITINERA_CONFIG?.SUPABASE_ANON_KEY || '',
          'authorization': `Bearer ${window.ITINERA_CONFIG?.SUPABASE_ANON_KEY || ''}`
        },
        body:JSON.stringify({question:text, lang:state.lang})
      });
      if(res.ok){
        const data = await res.json();
        if(data?.answer) return formatBotPlainText(data.answer)+botSourcesHTML(data.sources||[]);
      }
    }catch(error){
      console.warn('ItineraBot Edge fallback:', error);
    }
  }
  return botAnswer(text);
};

async function loadOfficialCoverageStatus(){
  if(!supabaseReady || !supabaseReady()) return;
  try{
    const rows = await sbFetch('/rest/v1/itinera_source_coverage?select=*&order=scope.asc&limit=100');
    state.officialCoverage = rows || [];
    const badge=document.getElementById('updateBadge');
    if(badge && rows?.length){
      const reviewed = rows.filter(r => String(r.current_status||'').includes('verified') || String(r.current_status||'').includes('in_progress')).length;
      badge.title = `${badge.title || ''} · Cobertura oficial: ${reviewed}/${rows.length} bloques en progreso/verificados`;
    }
  }catch(e){}
}

init = (function(previousInit){
  return async function(){
    previousInit();
    setTimeout(loadOfficialCoverageStatus, 1200);
  };
})(init);




/* ITINERA v0.18 · ItineraBot corrected for GitHub Pages + Supabase Edge Function */
itineraBotEndpoint = function(){
  const cfg = window.ITINERA_CONFIG || {};
  if(cfg.ITINERABOT_ENDPOINT) return cfg.ITINERABOT_ENDPOINT;
  if(cfg.SUPABASE_URL) return String(cfg.SUPABASE_URL).replace(/\/+$/,'') + '/functions/v1/itinerabot';
  return '';
}
publicBotSources = function(sources=[]){
  return (sources || []).filter(s => {
    const id = String(s.id || '').toLowerCase();
    const cat = String(s.category || '').toLowerCase();
    return !id.startsWith('openai-') && cat !== 'tecnica' && cat !== 'técnica';
  });
}
botSourcesHTML = function(sources=[]){
  return publicBotSources(sources).map(s=>`<a class="source-link" target="_blank" rel="noopener noreferrer" href="${s.url}"><strong>${escapeHTML(s.title||s.url)}</strong><span>${escapeHTML(s.usefulness||s.use||'Fonte oficial')}</span></a>`).join('');
}
friendlyStudyAnswer = function(program){
  if(!program) return '';
  const subjects = (program.subjects || []).filter(Boolean);
  const ponders = (program.ponderation_subjects || []).map(x => typeof x === 'string' ? x : (x.subject || x.name || '')).filter(Boolean);
  return `<article class="bot-study-answer">
    <h3>${escapeHTML(program.name)}</h3>
    <p><strong>${escapeHTML(program.level || '')}</strong>${program.family ? ` · ${escapeHTML(program.family)}` : ''}</p>
    ${program.route ? `<p><strong>Ruta orientativa:</strong> ${escapeHTML(program.route)}</p>` : ''}
    ${subjects.length ? `<p><strong>Materias/base recomendable:</strong> ${subjects.map(escapeHTML).join(', ')}</p>` : ''}
    ${ponders.length ? `<p><strong>Materias que pueden ponderar o deben revisarse:</strong> ${ponders.map(escapeHTML).join(', ')}</p>` : ''}
    ${program.regulated ? `<p><strong>Información importante:</strong> ${escapeHTML(program.regulated)}</p>` : ''}
    <p class="warning-box small">Para plazas, centros, notas de corte, ponderaciones exactas o convocatoria vigente, comprueba siempre la fuente oficial enlazada.</p>
    ${sourceLinks(program.sources || [])}
  </article>`;
}
smartLocalBotAnswer = async function(text){
  const q = normalise(text);
  let list = [];
  try { list = await supabaseSearchStudies(text,'all','all',8); } catch(e) {}
  if(!list.length) list = programs(text,'all','all').slice(0,8);
  const p = list[0];

  if(q.includes('matematic') && q.includes('psicolog')){
    return `<p>Si quieres Psicología pero las matemáticas no se te dan bien, conviene comparar tres elementos: ponderación oficial, nota realista que puedes obtener y base académica que te aporta cada materia. En Galicia debes comprobar la tabla CIUG vigente. Una materia que pondera 0,2 no siempre es la mejor opción si previsiblemente vas a obtener una calificación muy baja. Revisa también Biología, Matemáticas Aplicadas a las Ciencias Sociales II u otras materias que aparezcan vinculadas al grado y campus concreto.</p>${sourceLinks(['ciug-ponderaciones-2026','ciug-admision','qedu','ruct'])}`;
  }

  if((q.includes('medicina') || q.includes('biologia') || q.includes('psicologia') || q.includes('derecho') || q.includes('arquitectura') || q.includes('criminologia') || q.includes('electricidad') || q.includes('soldadura') || q.includes('carpinteria')) && p && p.score > .25){
    return friendlyStudyAnswer(p);
  }

  if(q.includes('nota') || q.includes('corte') || q.includes('ponder')){
    return `<p>Las notas de corte y las ponderaciones cambian por curso, grado, campus y convocatoria. En Galicia deben comprobarse en CIUG. Si indicas el grado exacto, ITINERA puede ayudarte a localizar la ruta de consulta y las materias que conviene revisar.</p>${sourceLinks(['ciug-admision','ciug-ponderaciones-2026','qedu'])}`;
  }

  if(q.includes('beca') || q.includes('neae')){
    return document.getElementById('scholarshipCards')?.innerHTML || `<p>Las becas oficiales dependen de convocatoria, nivel educativo, requisitos económicos, académicos y situación personal. Debe revisarse el portal oficial de becas del Ministerio y, cuando proceda, la información autonómica vigente.</p>${sourceLinks(['becas-portada','beca-general','beca-neae'])}`;
  }

  if(q.includes('discapacidad') || q.includes('deportista') || q.includes('cupo')){
    return document.getElementById('reservedCards')?.innerHTML || `<p>Existen cupos o reservas específicas en ciertos procesos de admisión, pero dependen del tipo de enseñanza y convocatoria. Hay que comprobar porcentaje, documentación y procedimiento en la fuente oficial vigente.</p>${sourceLinks(['ciug-admision'])}`;
  }

  if(p && p.score > .32) return friendlyStudyAnswer(p);

  return `<p>No he encontrado una ficha suficientemente precisa en la base oficial incorporada. No voy a inventar la respuesta. Prueba con el nombre exacto del estudio, familia profesional o etapa, o revisa las fuentes oficiales siguientes.</p>${sourceLinks(['todofp-familias','xunta-fp-oferta','qedu','ruct','ciug-admision'])}`;
}

askItineraBot = async function(text){
  const endpoint = itineraBotEndpoint();
  if(endpoint){
    try{
      const res = await fetch(endpoint, {
        method:'POST',
        headers:{
          'content-type':'application/json',
          'apikey': window.ITINERA_CONFIG?.SUPABASE_ANON_KEY || '',
          'authorization': `Bearer ${window.ITINERA_CONFIG?.SUPABASE_ANON_KEY || ''}`
        },
        body: JSON.stringify({question:text, lang:state.lang})
      });
      if(res.ok){
        const data = await res.json();
        if(data?.answer){
          return formatBotPlainText(data.answer) + botSourcesHTML(data.sources || []);
        }
      } else {
        console.warn('ItineraBot Edge HTTP', res.status, await res.text().catch(()=>''));
      }
    }catch(error){
      console.warn('ItineraBot Edge unavailable, using local fallback:', error);
    }
  }
  return await smartLocalBotAnswer(text);
};



/* ITINERA v0.18.1 · hard override: no technical bot answers, no OpenAI technical source cards */
(function(){
  const TECH_SOURCE_IDS = new Set(['openai-responses','openai-vector-stores']);
  function stripTechnicalSources(){
    try{
      if(state?.data?.official_sources){
        state.data.official_sources = state.data.official_sources.filter(s => !TECH_SOURCE_IDS.has(String(s.id||'')) && !['tecnica','técnica'].includes(String(s.category||'').toLowerCase()));
      }
    }catch(e){}
  }
  function endpoint(){
    const cfg = window.ITINERA_CONFIG || {};
    if(cfg.ITINERABOT_ENDPOINT) return cfg.ITINERABOT_ENDPOINT;
    if(cfg.SUPABASE_URL) return String(cfg.SUPABASE_URL).replace(/\/+$/,'') + '/functions/v1/itinerabot';
    return '';
  }
  function cleanSources(sources=[]){
    return (sources||[]).filter(s=>{
      const id=String(s.id||'').toLowerCase();
      const cat=String(s.category||'').toLowerCase();
      return !TECH_SOURCE_IDS.has(id) && cat!=='tecnica' && cat!=='técnica';
    });
  }
  function cleanSourceLinks(sources=[]){
    return cleanSources(sources).map(s=>`<a class="source-link" target="_blank" rel="noopener noreferrer" href="${s.url}"><strong>${escapeHTML(s.title||s.url)}</strong><span>${escapeHTML(s.usefulness||s.use||'Fonte oficial')}</span></a>`).join('');
  }
  function htmlFromStudy(p){
    if(!p) return '';
    const subjects=(p.subjects||[]).filter(Boolean);
    const ponders=(p.ponderation_subjects||[]).map(x=>typeof x==='string'?x:(x.subject||x.name||'')).filter(Boolean);
    return `<article class="bot-study-answer result-card">
      <h3>${escapeHTML(p.name)}</h3>
      <p><strong>${escapeHTML(p.level||'')}</strong>${p.family ? ` · ${escapeHTML(p.family)}` : ''}</p>
      ${p.route ? `<p><strong>Ruta orientativa:</strong> ${escapeHTML(p.route)}</p>` : ''}
      ${subjects.length ? `<p><strong>Materias/base recomendable:</strong> ${subjects.map(escapeHTML).join(', ')}</p>` : ''}
      ${ponders.length ? `<p><strong>Materias que pueden ponderar o deben revisarse:</strong> ${ponders.map(escapeHTML).join(', ')}</p>` : ''}
      ${p.regulated ? `<p><strong>Información importante:</strong> ${escapeHTML(p.regulated)}</p>` : ''}
      <p class="warning-box small">Para plazas, centros, notas de corte, ponderaciones exactas o convocatoria vigente, comprueba siempre la fuente oficial enlazada.</p>
      ${sourceLinks((p.sources||[]).filter(id=>!TECH_SOURCE_IDS.has(String(id))))}
    </article>`;
  }
  async function localAnswer(text){
    stripTechnicalSources();
    const q=normalise(text);
    let list=[];
    try{ if(typeof supabaseSearchStudies==='function') list=await supabaseSearchStudies(text,'all','all',8); }catch(e){}
    if(!list.length) list=programs(text,'all','all').slice(0,8);
    const p=list[0];

    if(q.includes('matematic') && q.includes('psicolog')){
      return `<p>Si quieres estudiar Psicología pero las matemáticas no se te dan bien, no conviene decidir solo por la ponderación. Compara la ponderación oficial de cada materia, la nota realista que puedes obtener y la base que te aporta para el grado. En Galicia debes comprobar la tabla vigente de la CIUG para el grado y campus concretos. Una materia con mayor ponderación puede no ser la opción más rentable si previsiblemente obtendrás una calificación baja.</p>${sourceLinks(['ciug-ponderaciones-2026','ciug-admision','qedu','ruct'])}`;
    }
    if(q.includes('nota') || q.includes('corte') || q.includes('ponder')){
      return `<p>Las notas de corte y las ponderaciones cambian por curso, convocatoria, universidad, campus y grado. En Galicia deben comprobarse en CIUG. ITINERA puede orientarte, pero no debe sustituir la consulta oficial vigente.</p>${sourceLinks(['ciug-admision','ciug-ponderaciones-2026','qedu'])}`;
    }
    if(q.includes('beca') || q.includes('neae')){
      return document.getElementById('scholarshipCards')?.innerHTML || `<p>Las becas oficiales dependen de convocatoria, nivel educativo y requisitos económicos, académicos y personales. Revisa siempre el portal oficial de Becas Educación y la convocatoria vigente.</p>${sourceLinks(['becas-portada','beca-general','beca-neae'])}`;
    }
    if(q.includes('discapacidad') || q.includes('deportista') || q.includes('cupo')){
      return document.getElementById('reservedCards')?.innerHTML || `<p>Existen cupos o reservas específicas en determinados procesos de admisión, pero dependen de la enseñanza, convocatoria y documentación. No implican plaza automática. Consulta la fuente oficial del procedimiento aplicable.</p>${sourceLinks(['ciug-admision'])}`;
    }
    if(p && Number(p.score||0)>.25) return htmlFromStudy(p);
    return `<p>No he encontrado una ficha suficientemente precisa en la base oficial incorporada. No voy a inventar la respuesta. Prueba con el nombre exacto del estudio, familia profesional o etapa, o revisa las fuentes oficiales.</p>${sourceLinks(['todofp-familias','xunta-fp-oferta','qedu','ruct','ciug-admision'])}`;
  }
  window.ITINERA_LOCAL_BOT_VERSION='0.18.1';
  botAnswer = function(text){ return localAnswer(text); };
  askItineraBot = async function(text){
    stripTechnicalSources();
    const url=endpoint();
    if(url){
      try{
        const res=await fetch(url,{
          method:'POST',
          headers:{
            'content-type':'application/json',
            'apikey': window.ITINERA_CONFIG?.SUPABASE_ANON_KEY || '',
            'authorization': `Bearer ${window.ITINERA_CONFIG?.SUPABASE_ANON_KEY || ''}`
          },
          body:JSON.stringify({question:text,lang:state.lang})
        });
        if(res.ok){
          const data=await res.json();
          if(data?.answer) return formatBotPlainText(data.answer)+cleanSourceLinks(data.sources||[]);
        }
      }catch(e){
        console.warn('ItineraBot Edge no disponible; usando fallback local v0.18.1', e);
      }
    }
    return await localAnswer(text);
  };
  init = (function(previousInit){
    return async function(){
      previousInit();
      stripTechnicalSources();
      const badge=document.getElementById('updateBadge');
      if(badge) badge.title=(badge.title||'')+' · ITINERA v0.18.1';
    };
  })(init);
})();


/* ITINERA v0.20 · cobertura visible, depuración FP y fichas más claras */
(function(){
  const STATUS_LABELS = {
    imported_needs_review: 'Importado · revisar',
    in_progress: 'En progreso',
    pending: 'Pendiente',
    verified: 'Verificado',
    verified_official: 'Verificado',
    seed_v0_17: 'Base inicial',
    seed_v0_16_1: 'Base inicial'
  };
  function statusLabel(status=''){
    const key = String(status || '').trim();
    return STATUS_LABELS[key] || key.replaceAll('_',' ') || 'Dato incorporado';
  }
  function statusClass(status=''){
    const s=String(status||'').toLowerCase();
    if(s.includes('verified')) return 'status-ok';
    if(s.includes('imported') || s.includes('progress')) return 'status-progress';
    if(s.includes('pending')) return 'status-pending';
    return 'status-neutral';
  }
  function niceTypeLabel(type){
    return type==='fpb'?'FP · Grado básico':
      type==='fpgm'?'FP · Grado medio':
      type==='fpgs'?'FP · Grado superior':
      type==='curso-especializacion-fp'?'FP · Curso de especialización':
      type==='grado'?'Universidad · Grado':
      type==='master'?'Universidad · Máster':'Otros estudios';
  }
  function studyQualityNote(p){
    const q = p.data_quality || '';
    if(String(q).includes('imported')) return 'Ficha importada desde fuente oficial. Debe verificarse la oferta concreta, plazas, modalidad y centro en la fuente vigente.';
    if(String(q).includes('seed')) return 'Ficha inicial curada manualmente. Revisa la fuente oficial antes de tomar decisiones académicas.';
    return 'Ficha conectada a la base de ITINERA. Comprueba siempre datos cambiantes en la fuente oficial.';
  }
  function coverageHTML(){
    const studies = state.data?.studies || [];
    const total = studies.length;
    const byType = studies.reduce((acc,p)=>{ const k=niceTypeLabel(p.type); acc[k]=(acc[k]||0)+1; return acc; },{});
    const pendingFamily = studies.filter(p=>String(p.family||'').toLowerCase().includes('pendiente')).length;
    const imported = studies.filter(p=>String(p.data_quality||'').includes('imported')).length;
    const docs = state.officialDocumentsCount || null;
    const cov = state.officialCoverage || [];
    return `<section class="coverage-panel" id="coveragePanel">
      <div class="coverage-head">
        <p class="eyebrow">Cobertura oficial</p>
        <h2>Estado actual do catálogo</h2>
        <p>ITINERA distingue entre datos xa importados, bloques en revisión e información que debe comprobarse na fonte oficial vixente.</p>
      </div>
      <div class="coverage-metrics">
        <article><strong>${total}</strong><span>estudos na base</span></article>
        <article><strong>${imported}</strong><span>importados desde fonte oficial</span></article>
        <article><strong>${pendingFamily}</strong><span>con familia pendente</span></article>
        <article><strong>${docs ?? '—'}</strong><span>documentos oficiais</span></article>
      </div>
      <div class="coverage-type-grid">${Object.entries(byType).sort().map(([k,v])=>`<div><strong>${escapeHTML(k)}</strong><span>${v}</span></div>`).join('')}</div>
      ${cov.length ? `<div class="coverage-blocks">${cov.map(row=>`<article class="${statusClass(row.current_status)}"><strong>${escapeHTML(row.scope||'Bloque')}</strong><span>${escapeHTML(statusLabel(row.current_status))}</span><p>${escapeHTML(row.notes||'')}</p></article>`).join('')}</div>` : `<p class="warning-box small">Cobertura detallada pendente de cargar desde Supabase.</p>`}
    </section>`;
  }
  function injectCoveragePanel(){
    const homeQuestions = document.getElementById('homeQuestions');
    if(!homeQuestions) return;
    let panel = document.getElementById('coveragePanel');
    if(panel) panel.remove();
    homeQuestions.insertAdjacentHTML('afterend', coverageHTML());
  }
  async function loadOfficialDocsCount(){
    if(!supabaseReady || !supabaseReady()) return;
    try{
      const rows = await sbFetch('/rest/v1/itinera_official_documents?select=id&limit=1000');
      state.officialDocumentsCount = Array.isArray(rows) ? rows.length : null;
    }catch(e){}
  }
  const oldProgramCard = programCard;
  programCard = function(p,approx=false){
    const subjects = (p.subjects||[]).filter(Boolean);
    const ponders = (p.ponderation_subjects||[]).map(x=>typeof x==='string'?x:(x.subject||x.name||'')).filter(Boolean);
    return `<article class="result-card enhanced-card">${approx?`<p class="eyebrow">${T('maybe')}: ${escapeHTML(p.name)}</p>`:''}
      <div class="study-card-head">
        <div>
          <h3>${escapeHTML(p.name)}</h3>
          <div class="badges">
            <span class="badge">${escapeHTML(p.level||niceTypeLabel(p.type))}</span>
            <span class="badge">${escapeHTML(p.family||'Familia por revisar')}</span>
            <span class="badge ${statusClass(p.data_quality)}">${escapeHTML(statusLabel(p.data_quality))}</span>
          </div>
        </div>
      </div>
      ${p.route?`<p><strong>${T('route')}:</strong> ${escapeHTML(p.route)}</p>`:''}
      ${subjects.length?`<p><strong>${T('subjects')}:</strong> ${subjects.map(escapeHTML).join(', ')}</p>`:''}
      ${ponders.length?`<p><strong>Materias que poden ponderar máis:</strong> ${ponders.map(escapeHTML).join(', ')}</p>`:''}
      ${p.regulated?`<p><strong>${T('important')}:</strong> ${escapeHTML(p.regulated)}</p>`:''}
      ${p.demand?`<p><strong>Demanda / emprego:</strong> ${escapeHTML(p.demand)}</p>`:''}
      ${availabilityHTML(p)}
      <p class="warning-box small">${escapeHTML(studyQualityNote(p))}</p>
      <div class="result-actions">
        <button type="button" class="button pdf-button" onclick="exportPDF('studyResults','ITINERA · ${escapeHTML(p.name)}')">${T('pdf')}</button>
        <button type="button" class="button action-sim" onclick="simulateProgram('${p.id}')">${T('sim')}</button>
      </div>
      ${sourceLinks(p.sources||[])}
    </article>`;
  };
  const oldGroupedStudiesHTML = groupedStudiesHTML;
  groupedStudiesHTML = function(list){
    const byType = {};
    list.forEach(p=>{
      const typeLabel = niceTypeLabel(p.type);
      byType[typeLabel] ||= {};
      const fam = p.family || 'Familia por revisar';
      byType[typeLabel][fam] ||= [];
      byType[typeLabel][fam].push(p);
    });
    return Object.entries(byType).sort().map(([type,families])=>`<section class="studies-group"><h2>${escapeHTML(type)}</h2>${Object.entries(families).sort().map(([fam,items])=>`<details open class="family-group ${String(fam).toLowerCase().includes('pendiente')?'needs-review':''}"><summary>${escapeHTML(fam)} <span>${items.length}</span></summary><div class="family-study-grid">${items.map(p=>`<button class="study-list-item" type="button" onclick="showStudySheet('${p.id}')"><strong>${escapeHTML(p.name)}</strong><span>${escapeHTML(p.level)} · ${escapeHTML(p.family || 'Familia por revisar')}</span></button>`).join('')}</div></details>`).join('')}</section>`).join('');
  };
  showStudySheet = function(id){
    const p = state.data.studies.find(x=>x.id===id);
    if(!p) return;
    document.getElementById('studySheetContent').innerHTML = programCard(p);
    openModal('studySheetModal');
  };
  const previousLoadCoverage = typeof loadOfficialCoverageStatus === 'function' ? loadOfficialCoverageStatus : async function(){};
  loadOfficialCoverageStatus = async function(){
    await previousLoadCoverage();
    await loadOfficialDocsCount();
    injectCoveragePanel();
  };
  const previousInit = init;
  init = async function(){
    previousInit();
    setTimeout(async()=>{ await loadOfficialCoverageStatus(); injectCoveragePanel(); }, 1400);
  };
})();


/* ITINERA v0.21 · Universidad, RUCT/QEDU, másteres habilitantes y CIUG */
